{{ config(materialized='view') }}

SELECT
    RECORD_CREATE_TMS,
    MARK_CD,
    EQPUN_NBR
FROM {{ ref('stg_eqpmnt_non_rgstrd') }}
WHERE EDW_UPDATE_TMS > DATEADD('HOUR', -1, CURRENT_TIMESTAMP())
  AND NOT EXISTS (
      SELECT 1
      FROM {{ ref('stg_eqpmnt_aar_base') }} aarb
      WHERE aarb.MARK_CD = stg_eqpmnt_non_rgstrd.MARK_CD
        AND aarb.EQPUN_NBR = stg_eqpmnt_non_rgstrd.EQPUN_NBR
  )
